#include<bits/stdc++.h>
using namespace std;
const int MAXN=3005,B=51971;const long long MOD=2005091020050911;
char a[MAXN],b[MAXN];int n;long long t[MAXN*MAXN];
int main(void){
	scanf("%d%s%s",&n,a+1,b+1);
	for(int i=1;i<=n;++i){
		long long v=0;int p=1;
		for(int j=i;j<=n;++j){
			while(p<=n&&a[p]!=b[j])++p;
			if(p>n)break;++p;
			v=(1ll*v*B+b[j]-'a'+1)%MOD;t[++t[0]]=v;
		}
	}
	sort(t+1,t+t[0]+1);
	printf("%d\n",unique(t+1,t+t[0]+1)-t-1);
	return false;
}
